package ru.memearena.scout.application; import org.slf4j.*; import org.springframework.scheduling.annotation.Scheduled; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.meme.domain.Meme; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.scout.domain.*; import ru.memearena.scout.infrastructure.*; import java.time.*; import java.util.*;
@Service public class PredictionResolutionService{ private static final Logger log=LoggerFactory.getLogger(PredictionResolutionService.class); public record Result(int processedMemes,int resolvedPredictions,int successCount,int failedCount,int expiredCount){} private final MemePredictionRepository preds; private final MemeRepository memes; private final UserScoutStatsRepository statsRepo; private final ScoutPointEventRepository events; private final ScoutPolicies policies; private final AchievementService ach; private final Clock clock; private final ScoutProperties props; public PredictionResolutionService(MemePredictionRepository p,MemeRepository m,UserScoutStatsRepository s,ScoutPointEventRepository e,ScoutPolicies pol,AchievementService a,Clock c,ScoutProperties props){this.preds=p;this.memes=m;this.statsRepo=s;this.events=e;this.policies=pol;this.ach=a;this.clock=c;this.props=props;} public Result runOnce(){int pm=0,r=0,su=0,fa=0,ex=0; for(UUID id:preds.pendingMemeIds()){try{var x=processMeme(id); if(x.resolvedPredictions()>0){pm++;r+=x.resolvedPredictions();su+=x.successCount();fa+=x.failedCount();ex+=x.expiredCount();}}catch(Exception e){log.warn("Scout resolver failed for meme {}",id,e);}} return new Result(pm,r,su,fa,ex);} @Transactional Result processMeme(UUID id){Instant now=Instant.now(clock); Meme m=memes.findById(id).orElse(null); if(m==null)return new Result(0,0,0,0,0); PredictionStatus status=null; String reason=""; if(policies.expired(m,now)){status=PredictionStatus.EXPIRED;reason="expired_before_minimum_battles";} else if(policies.resolvable(m,now)){status=policies.success(m,memes.findApprovedByCohort(m.getApprovalCohortDate()))?PredictionStatus.SUCCESS:PredictionStatus.FAILED;reason="cohort_resolution";} else return new Result(0,0,0,0,0); int su=0,fa=0,ex=0,total=0; var list=preds.findByMemeIdAndStatusOrderByUserIdAscPredictedAtAsc(id,PredictionStatus.PENDING); for(var pr:list){var st=statsRepo.findById(pr.getUserId()).orElseGet(()->new UserScoutStats(pr.getUserId(),now)); int pts=status==PredictionStatus.SUCCESS?policies.points(pr,m):0; pr.resolve(status,pts,reason,now); if(status==PredictionStatus.SUCCESS){st.success(pts,now); events.save(new ScoutPointEvent(UUID.randomUUID(),pr.getUserId(),pr.getId(),pts,"PREDICTION_SUCCESS",now)); ach.unlock(pr.getUserId(),"FIRST_HIT",now); if(Duration.between(m.getApprovedAt(),pr.getPredictedAt()).toMinutes()<=60)ach.unlock(pr.getUserId(),"EARLY_BIRD",now); if(st.getCurrentSuccessStreak()>=3)ach.unlock(pr.getUserId(),"STREAK_3",now); if(st.getCurrentSuccessStreak()>=10)ach.unlock(pr.getUserId(),"STREAK_10",now); switch(ScoutRank.fromPoints(st.getScoutPoints())){case SCOUT -> ach.unlock(pr.getUserId(),"SCOUT_RANK",now); case TREND_HUNTER -> {ach.unlock(pr.getUserId(),"SCOUT_RANK",now);ach.unlock(pr.getUserId(),"TREND_HUNTER_RANK",now);} case MEME_ORACLE -> {ach.unlock(pr.getUserId(),"SCOUT_RANK",now);ach.unlock(pr.getUserId(),"TREND_HUNTER_RANK",now);ach.unlock(pr.getUserId(),"MEME_ORACLE_RANK",now);} default -> {}} su++;} else if(status==PredictionStatus.FAILED){st.failed(now);fa++;} else {st.expired(now);ex++;} statsRepo.save(st); total++; } return new Result(total>0?1:0,total,su,fa,ex);} @Scheduled(fixedDelayString="${app.scout.resolver.fixed-delay:PT30M}") public void scheduled(){if(props.resolver.enabled)runOnce();} }
